import { PublicActionPage } from '@domain/publicActionPage';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import {
  FormAddressControl,
  FormAddressControlProps,
  FormPostalCodeControl,
} from 'src/builder/PublicActionPage/components/AddressControl';

export type Props = {
  actionPage?: PublicActionPage;
  forceDisplay?: boolean;
  isPreview?: boolean;
  labelKey?: 'organization' | 'business' | 'pac' | 'employer' | 'street';
  showLine2?: boolean;
} & Pick<FormAddressControlProps, 'fieldPrefix' | 'fieldPrefixDelimiter'>;

export const AddressField = ({
  actionPage,
  fieldPrefix = 'addressAttributes',
  fieldPrefixDelimiter = '.',
  forceDisplay,
  isPreview = false,
  labelKey,
  showLine2,
}: Props) => {
  const { trigger, watch } = useFormContext();
  const { t } = useTranslation('customFields');
  const donorProfile = isPreview ? null : watch('donorProfile');
  const expressCheckoutMethod = watch('expressCheckoutMethod');
  const makeDonationAs = watch('makeDonationAs');
  const country = watch('addressAttributes.country');
  const promoCode = watch('promoCode');
  const totalPrice = watch('totalPrice');
  const isDonation = isDonationPage(actionPage?.pageType);

  // force re-validation for postal code whenever the country changes
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    trigger('addressAttributes.postalCode');
  }, [country, trigger]);

  const {
    addressLabel,
    addressType,
    displayAddress = true,
    regions,
    requireAddress,
  } = actionPage?.fieldConfiguration || {};

  const addressSectionLabel = useMemo(
    () =>
      makeDonationAs === 'organization'
        ? 'organization'
        : makeDonationAs === 'business'
          ? 'business'
          : makeDonationAs === 'pac'
            ? 'pac'
            : addressLabel,
    [makeDonationAs, addressLabel]
  );

  const label = useMemo(
    () => t(`address.${(labelKey || addressSectionLabel) ?? 'street'}`),
    [addressSectionLabel, labelKey, t]
  );

  const allowedCountries = useMemo(
    () =>
      regions?.includes('IN')
        ? undefined
        : regions?.length
          ? regions
          : addressType === 'complete'
            ? ['US']
            : undefined,
    [addressType, regions]
  ) as FormAddressControlProps['allowedCountries'];

  useEffect(() => {
    if (promoCode && totalPrice === 0) {
      trigger('addressAttributes');
    }
  }, [trigger, promoCode, totalPrice]);

  if (
    !displayAddress ||
    (donorProfile &&
      donorProfile.line1 &&
      donorProfile.city &&
      donorProfile.region &&
      donorProfile.postalCode &&
      donorProfile.country) ||
    (addressType === 'zip' && donorProfile && donorProfile.postalCode)
  ) {
    return null;
  }

  return !expressCheckoutMethod || forceDisplay ? (
    <div className="-mb-2 flex flex-col items-stretch">
      {addressType === 'zip' ? (
        <FormPostalCodeControl
          isRequired={isDonation || requireAddress}
          name={`${fieldPrefix}${fieldPrefixDelimiter}postalCode`}
        />
      ) : (
        <FormAddressControl
          actionPage={actionPage}
          allowedCountries={allowedCountries}
          fieldPrefix={fieldPrefix}
          fieldPrefixDelimiter={fieldPrefixDelimiter}
          isRequired={!(promoCode && totalPrice === 0) && (isDonation || requireAddress)}
          label={label}
          showLine2={showLine2}
        />
      )}
    </div>
  ) : null;
};

