import { PublicActionPage } from '@domain/publicActionPage';
import { useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import {
  FormAddressControl,
  FormAddressControlProps,
  FormPostalCodeControl,
} from '../../../../../../components/AddressControl';

export type AddressFieldProps = Pick<
  FormAddressControlProps,
  | 'fieldPrefix'
  | 'fieldPrefixDelimiter'
  | 'isRequired'
  | 'showLine2'
  | 'allowedCountries'
  | 'variant'
> & {
  actionPage?: PublicActionPage;
  addressLabel?: 'street' | 'mailing' | 'residential' | 'employer';
  addressType?: 'complete' | 'international' | 'zip';
  displayAddress?: boolean;
};

export const Address = ({
  actionPage,
  addressLabel,
  addressType,
  allowedCountries,
  displayAddress = true,
  fieldPrefix,
  fieldPrefixDelimiter,
  isRequired,
  showLine2,
  variant,
}: AddressFieldProps) => {
  const { watch } = useFormContext();
  const label = useMemo(() => {
    switch (addressLabel) {
      case 'employer':
        return 'Employer Address';
      case 'mailing':
        return 'Mailing Address';
      case 'residential':
        return 'Residential Address';
      case 'street':
      default:
        return 'Address';
    }
  }, [addressLabel]);
  const donorProfile = watch('donorProfile');

  if (
    !displayAddress ||
    (fieldPrefix === 'addressAttributes' &&
      donorProfile &&
      donorProfile.line1 &&
      donorProfile.city &&
      donorProfile.region &&
      donorProfile.postalCode &&
      donorProfile.country) ||
    (addressType === 'zip' && donorProfile && donorProfile.postalCode)
  ) {
    return null;
  }

  return addressType === 'zip' ? (
    <FormPostalCodeControl
      isRequired={isRequired}
      name={`${fieldPrefix}${fieldPrefixDelimiter}postalCode`}
    />
  ) : (
    <FormAddressControl
      actionPage={actionPage}
      allowedCountries={allowedCountries || (addressType === 'complete' ? ['US'] : undefined)}
      fieldPrefix={fieldPrefix}
      fieldPrefixDelimiter={fieldPrefixDelimiter}
      isRequired={isRequired}
      label={label}
      showLine2={showLine2}
      variant={variant}
    />
  );
};

